package be.schaubroeck.lpb.rkm.rekenmotor.voorbereiding;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.RkmCoreHrConfiguratie;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenAtoom;
import be.schaubroeck.lpb.rkm.rekenmotor.service.RekenmotorDtoConverter;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenTools;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.Opdracht;
import be.schaubroeck.lpb.tools.Opper;
import be.schaubroeck.lpb.tools.RegulAgenda;
import be.schaubroeck.lpb.tools.enumtypes.Rekengroep;
import be.schaubroeck.lpb.tools.service.OpdrachtService;
import be.schaubroeck.lpb.tools.service.RegulAgendaService;
import be.schaubroeck.lpb.tools.service.util.TemporalUtil;
import be.schaubroeck.temporal.interval.Eternity;
import be.schaubroeck.temporal.interval.Month;
import be.schaubroeck.util.persistence.Identifiable;
import com.google.common.collect.Ordering;
import com.google.common.collect.SetMultimap;
import com.google.common.collect.TreeMultimap;
import lombok.extern.slf4j.Slf4j;
import org.joda.time.LocalDate;
import org.joda.time.LocalDateTime;
import org.springframework.beans.factory.annotation.Autowired;

import java.util.Collection;
import java.util.List;
import java.util.Map;
import java.util.Objects;
import java.util.Set;
import java.util.function.Function;
import java.util.stream.Collectors;

import static java.util.stream.Collectors.toList;
import static java.util.stream.Collectors.toMap;

@Slf4j
public class RekenAtomenCollectorImp implements RekenAtomenCollector {

    @Autowired
    private RegulAgendaService regulAgendaService;

    @Autowired
    private OpdrachtService opdrachtService;

    @Override
    public SetMultimap<RekenAtoom, Integer> bepaalRekenAtomen(
            RekenVoorbereiding voorbereiding, LocalDateTime rekenTijdstip) {
        SetMultimap<RekenAtoom, Integer> atomenMap = TreeMultimap.create();
        List<Opdracht> opdrachten = voorbereiding.findOpdrachten();
        log.info("bepaalRekenAtomen opdrachten: {}", toStringOfIds(opdrachten));
        RekenTijd rekenTijd = voorbereiding.getRekenTijd(rekenTijdstip);
        SetMultimap<Integer, Integer> persoonIdToOpdrachtNrs = TreeMultimap.create();
        opdrachten.forEach(x -> persoonIdToOpdrachtNrs.put(x.getPersoon().getId(), x.getOpdrachtnr()));
        log.info("bepaalRekenAtomen rekenTijd: {}", rekenTijd);
        for (Integer persoonId : persoonIdToOpdrachtNrs.keySet()) {
            Set<Integer> opdrachtNrs = persoonIdToOpdrachtNrs.get(persoonId);
            atomenMap.putAll(new RekenAtoom(rekenTijd, persoonId), opdrachtNrs);
            if (voorbereiding.getMetRegulagenda()) {
                atomenMap.putAll(vindRegulAgendaAtomen(voorbereiding, persoonId, opdrachtNrs, rekenTijdstip));
            }
        }
        return atomenMap;
    }

    @Override
    public SetMultimap<RekenAtoom, Integer> bepaalRekenAtomenVoorHoedanigHeidOfRekenGroep(RekenVoorbereiding voorbereiding, LocalDateTime rekenTijdstip) {
        SetMultimap<RekenAtoom, Integer> atomenMap = TreeMultimap.create();
        Month maand = voorbereiding.getPeriode();
        log.info("Bepaal regulAgenda's voor periode: {}", maand);
        List<RegulAgenda> regulAgendas = regulAgendaService.findByPeriode(voorbereiding.getAdmin(), maand);
        Map<RegulAgenda, Opdracht> regulAgendaOpdrachtMap = regulAgendas.stream()
                .collect(toMap(Function.identity(),
                        regulAgenda -> getOpdrachtOpBasisVanRegulAgendaEnPersoon(voorbereiding, regulAgenda),
                        (x, y) -> y));

        log.info("Filter regulAgenda's op basis van hoedanigheid en rekengroep: {} ,{}", voorbereiding.getHoedanigheid(), voorbereiding.getRekengroep());
        List<RegulAgenda> filteredRegulAgendas = regulAgendaOpdrachtMap.keySet().stream()
                .filter(regulAgenda -> filterRegulAgendasOpBasisVanHoedanigheidEnRekengroep(voorbereiding, regulAgendaOpdrachtMap.get(regulAgenda)))
                .collect(toList());
        RekenTijd rekenTijd = voorbereiding.getRekenTijd(maand, rekenTijdstip);
        log.info("bepaalRekenAtomen rekenTijd voor hoedanigheid of rekengroep: {}", rekenTijd);
        filteredRegulAgendas.forEach(regulAgenda -> atomenMap.put(new RekenAtoom(rekenTijd, regulAgenda.getPersoon().getId()), regulAgenda.getOpdrachtNummer()));
        return atomenMap;
    }

    private Opdracht getOpdrachtOpBasisVanRegulAgendaEnPersoon(RekenVoorbereiding voorbereiding, RegulAgenda regulAgenda) {
        log.info("Haal opdracht op, op basis van opdrachtnummer en persoon : {} ,{}", regulAgenda.getOpdrachtNummer(), regulAgenda.getPersoon().getId());
        return TemporalUtil.getActualInterval(new Eternity(),
                () -> opdrachtService.getByPersoonOpdrachtNr(voorbereiding.getAdmin(), regulAgenda.getPersoon(), regulAgenda.getOpdrachtNummer(),
                        "opdrachtSlices, opperSlices{weddeBerekening}"));
    }

    private boolean filterRegulAgendasOpBasisVanHoedanigheidEnRekengroep(RekenVoorbereiding voorbereiding, Opdracht regulAgendaOpdracht) {
        boolean checkHoedanigheid = regulAgendaOpdracht.getHoedanigheid() == voorbereiding.getHoedanigheid();
        LocalDate selectieDatum = Ordering.natural().min(regulAgendaOpdracht.getEindDatum(), voorbereiding.getPeriode().getEnd());
        selectieDatum = Ordering.natural().max(regulAgendaOpdracht.getBeginDatum(), selectieDatum);
        Opper opper = RekenTools.findOpper(regulAgendaOpdracht, selectieDatum);
        Integer rekenGroep = opper.getWeddeBerekening().getRekenGroep();
        boolean checkRekenGroep = Rekengroep.getByCode(rekenGroep) == voorbereiding.getRekengroep();
        return checkHoedanigheid || checkRekenGroep;
    }

    private SetMultimap<RekenAtoom, Integer> vindRegulAgendaAtomen(
            RekenVoorbereiding voorbereiding, Integer persoonId, Set<Integer> opdrachtNrs, LocalDateTime rekenTijdstip) {
        SetMultimap<RekenAtoom, Integer> atomenMap = TreeMultimap.create();
        Admin admin = voorbereiding.getAdmin();
        List<RegulAgenda> agendas = regulAgendaService.findByPersoonIdAndOpdrachtNrBeforeDatum(admin, voorbereiding.getPeriode().getStart(), persoonId, opdrachtNrs);
        for (RegulAgenda agenda : agendas) {
            Month maandAgenda = new Month(agenda.getBeginDatum());
            while (maandAgenda.getEnd().compareTo(agenda.getEindDatum()) <= 0 && maandAgenda.getEnd().compareTo(voorbereiding.getPeriode().getEnd()) < 0) {
                RekenTijd rekenTijdAgenda = voorbereiding.getRekenTijd(maandAgenda, rekenTijdstip);
                atomenMap.put((new RekenAtoom(rekenTijdAgenda, persoonId)), agenda.getOpdrachtNummer());
                maandAgenda = new Month(maandAgenda.getStart().plusMonths(1));
            }
        }
        return atomenMap;
    }

    private <T extends Identifiable> String toStringOfIds(Collection<T> collecton) {
        return collecton.stream().map(T::getId).collect(Collectors.toSet()).toString();
    }

    @Override
    public boolean getGewijzigdeGegevens(
            RekenmotorDtoConverter converter, List<RkmCoreHrConfiguratie> rkmCoreHrConfiguraties, RekenVoorbereiding punt) {
        return rkmCoreHrConfiguraties.stream()
                .filter(rkmCoreHrConfiguratie -> Objects.equals(rkmCoreHrConfiguratie.getWerkgeverId(), converter.getWerkgeverId(punt)))
                .filter(rkmCoreHrConfiguratie -> filterOpRekentijd(rkmCoreHrConfiguratie, punt))
                .map(RkmCoreHrConfiguratie::isGewijzigdeGegevens)
                .findFirst()
                .orElse(false);
    }

    private boolean filterOpRekentijd(RkmCoreHrConfiguratie rkmCoreHrConfiguratie, RekenVoorbereiding voorbereiding) {
        Month periode = voorbereiding.getPeriode();
        return (rkmCoreHrConfiguratie.getActualFrom().isBefore(periode.getEnd()) || rkmCoreHrConfiguratie.getActualFrom().equals(periode.getEnd())) &&
                (rkmCoreHrConfiguratie.getActualTo().isAfter(periode.getStart()) || rkmCoreHrConfiguratie.getActualTo().equals(periode.getStart()));
    }
}
